namespace sv_b407be29275a4c1383ef43f0bfe849a6.Client.Models;

public sealed record Shipment(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

public sealed record StatusUpdate(
    string Status,
    string Location,
    DateTimeOffset Timestamp);

using sv_b407be29275a4c1383ef43f0bfe849a6.Client.Models;

namespace sv_b407be29275a4c1383ef43f0bfe849a6.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_b407be29275a4c1383ef43f0bfe849a6.Client.Models;
using sv_b407be29275a4c1383ef43f0bfe849a6.Client.Services;

namespace sv_b407be29275a4c1383ef43f0bfe849a6.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment(
            TrackingNumber: "PKG-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Order Placed", "New York, NY", new DateTimeOffset(2026, 5, 20, 10, 0, 0, TimeSpan.Zero)),
                new("Picked Up", "New York, NY", new DateTimeOffset(2026, 5, 21, 8, 30, 0, TimeSpan.Zero)),
                new("In Transit", "Chicago, IL", new DateTimeOffset(2026, 5, 23, 14, 15, 0, TimeSpan.Zero))
            }),
        ["PKG-002"] = new Shipment(
            TrackingNumber: "PKG-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 22, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Order Placed", "Seattle, WA", new DateTimeOffset(2026, 5, 18, 9, 0, 0, TimeSpan.Zero)),
                new("Picked Up", "Seattle, WA", new DateTimeOffset(2026, 5, 19, 7, 0, 0, TimeSpan.Zero)),
                new("In Transit", "Portland, OR", new DateTimeOffset(2026, 5, 20, 11, 0, 0, TimeSpan.Zero)),
                new("Out for Delivery", "San Francisco, CA", new DateTimeOffset(2026, 5, 22, 8, 0, 0, TimeSpan.Zero)),
                new("Delivered", "San Francisco, CA", new DateTimeOffset(2026, 5, 22, 11, 45, 0, TimeSpan.Zero))
            }),
        ["PKG-003"] = new Shipment(
            TrackingNumber: "PKG-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 6, 1, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Order Placed", "Dallas, TX", new DateTimeOffset(2026, 5, 25, 6, 0, 0, TimeSpan.Zero))
            })
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using sv_b407be29275a4c1383ef43f0bfe849a6.Client.Services;

namespace sv_b407be29275a4c1383ef43f0bfe849a6.Services;

public static class ShipmentApiEndpoints
{
    public static void MapShipmentApi(this WebApplication app)
    {
        app.MapGet("/api/shipments/{trackingNumber}", async (
            string trackingNumber,
            IShipmentService service,
            CancellationToken ct) =>
        {
            var shipment = await service.GetShipmentAsync(trackingNumber, ct);
            return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
        });
    }
}

using System.Net.Http.Json;
using sv_b407be29275a4c1383ef43f0bfe849a6.Client.Models;

namespace sv_b407be29275a4c1383ef43f0bfe849a6.Client.Services;

public sealed class HttpShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_b407be29275a4c1383ef43f0bfe849a6.Client.Models
@using sv_b407be29275a4c1383ef43f0bfe849a6.Client.Services
@rendermode InteractiveAuto
@implements IDisposable
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-message">
        <p>@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Status Updates</h3>
        <table>
            <thead>
                <tr>
                    <th>Timestamp</th>
                    <th>Status</th>
                    <th>Location</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.StatusUpdates)
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Status</td>
                        <td>@update.Location</td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override Task OnParametersSetAsync()
    {
        return LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — silently abandon
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || ex.CancellationToken != ct)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private Task RetryLoad() => LoadShipmentAsync();

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

